 // Variables
let EdgeFront: any;
let EdgeLeft: any;
let EdgeBack: any;  
let EdgeRight: any;
let EdgeJointValue: any;

 //---------------Get data from table BoardObjectMapping-----------------

let BoardObjectMapping = GlobalFunc.find_BoardObjectMapping(part.pa_Program, part.pa_TypeElement, part.pa_PartDesign, part._thickness, part.pa_TopColor, part.pa_BtmColor);


  // Attribute values for EdgeColor and EdgeClass
  EdgeFront = GlobalFunc.find_EdgeMapping(part.pa_EdgeFrontClass, part.pa_EdgeTechnology,part.pa_EdgeFrontColor, part._thickness)
  EdgeLeft = GlobalFunc.find_EdgeMapping(part.pa_EdgeLeftClass, part.pa_EdgeTechnology,part.pa_EdgeLeftColor, part._thickness)
  EdgeBack = GlobalFunc.find_EdgeMapping(part.pa_EdgeBackClass, part.pa_EdgeTechnology,part.pa_EdgeBackColor, part._thickness)
  EdgeRight = GlobalFunc.find_EdgeMapping(part.pa_EdgeRightClass, part.pa_EdgeTechnology,part.pa_EdgeRightColor, part._thickness)


let BoardLibrary = GlobalFunc.find_BoardLibrary(BoardObjectMapping.BoardId);           
//let GrainDirection = GlobalFunc.find_GrainDirection(BoardLibrary.Grain!,part.pa_PartGrain);

/*
let EdgeFrontLibrary = GlobalFunc.find_EdgeLibrary(EdgeFront.EdgeId!)
let EdgeLeftLibrary = GlobalFunc.find_EdgeLibrary(EdgeLeft.EdgeId!)
let EdgeBackLibrary = GlobalFunc.find_EdgeLibrary(EdgeBack.EdgeId!)
let EdgeRightLibrary = GlobalFunc.find_EdgeLibrary(EdgeRight.EdgeId!)
*/


 EdgeJointValue = part.pa_EdgeJointType


let EdgeJoint = GlobalFunc.find_EdgeJointTypeConstruction(EdgeJointValue,part.pa_EdgePosType)


//---------------Set attributes of the board----------------------------

this.bom_Material = BoardLibrary.MaterialCode;
this.bom_Width = part._depth;
this.bom_Length = part._width;
this.bom_Finalthk = part._thickness;
this.bom_BoardType =  BoardLibrary.BoardType!;
//this.bom_GrainOrientation = GrainDirection.GrainDirection;
this.bom_Route = 'DemoRoute';
this.bom_EdgeLeft = EdgeLeft.EdgeId!;
this.bom_EdgeRight = EdgeRight.EdgeId!;
this.bom_EdgeBack = EdgeBack.EdgeId!;
this.bom_EdgeFront = EdgeFront.EdgeId!;
this.bom_EdgeJointFrontLeft = EdgeJoint.EdgeJointFrontLeft;
this.bom_EdgeJointLeftBack = EdgeJoint.EdgeJointLeftBack;
this.bom_EdgeJointBackRight = EdgeJoint.EdgeJointBackRight;
this.bom_EdgeJointRightFront = EdgeJoint.EdgeJointRightFront;
this.bom_EdgeShape = EdgeJoint.EdgeShape;
this.bom_EdgeTransition = EdgeJoint.EdgeCode

